# scripts/check-runbooks.py
import sys, re
from pathlib import Path

REQUIRED_SECTIONS = {"Symptom", "Severity", "Diagnostic Steps", "Escalation"}
HEADING_RE = re.compile(r'^#{1,3}\s+(.+)', re.MULTILINE)

def check_runbook(path: Path) -> list[str]:
    text = path.read_text()
    headings = {m.group(1).strip() for m in HEADING_RE.finditer(text)}
    missing = REQUIRED_SECTIONS - headings
    return [f"{path.name}: missing section '{s}'" for s in sorted(missing)]

if __name__ == "__main__":
    runbook_dir = Path(sys.argv[1])
    errors = []
    for runbook in runbook_dir.glob("*.md"):
        errors.extend(check_runbook(runbook))
    if errors:
        for e in errors:
            print(f"ERROR: {e}")
        sys.exit(1)
    print(f"All {len(list(runbook_dir.glob('*.md')))} runbooks pass completeness check.")
